mapper.select:
SELECT f.foodName
FROM food f
JOIN twenty_attribute t ON f.foodId = t.foodId

     AND f.category = 'Korean food' 
     AND f.category != 'Korean food' 
     AND f.category = 'Western food' 
     AND f.category != 'Western food' 
     AND f.category = 'Chinese food' 
     AND f.category != 'Chinese food' 
     AND f.category = 'Japanese food' 
     AND f.category != 'Japanese food' 
     AND f.category = 'Asian food' 
     AND f.category != 'Asian food' 
     AND t.is_soup = #{isSoup} 
     AND t.is_spicy = #{isSpicy} 
     AND t.is_fried = #{isFried} 
     AND t.is_roasted = #{isRoasted} 
     AND t.has_pork = #{hasPork} 
     AND t.has_beef = #{hasBeef} 
     AND t.has_noodle = #{hasNoodle} 
     AND t.has_rice = #{hasRice} 
     AND t.has_flour = #{hasFlour} 
     AND t.has_seafood = #{hasSeafood} 
     AND t.has_chicken = #{hasChicken} 
     AND t.is_veggie = #{isVeggie} 
     AND t.is_cold = #{isCold} 
     AND t.is_greasy = #{isGreasy} 
     AND t.is_sweet = #{isSweet} 
     AND t.is_solo = #{isSolo} 
     AND t.is_sharing = #{isSharing} 
     AND t.is_heavy = #{isHeavy}

SELECT imagePath
FROM food
WHERE foodName = #{foodName}

SELECT foodId, foodName, category, description, imagePath
FROM food
WHERE foodName = #{name}

SELECT * FROM food
AND category = #{category}
ORDER BY RAND() LIMIT 1
